package main

import "fmt"

func join(sep string, words ...string) string {
    result := ""
    for i, word := range words {
        if i > 0 {
            result += sep
        }
        result += word
    }
    return result
}

func main() {
    fmt.Println(join(", ", "apple", "banana", "cherry"))

    // Pass slice with ...
    fruits := []string{"date", "elderberry", "fig"}
    fmt.Println(join(" - ", fruits...))

    fmt.Println(join(" ")) // no words
}
